import React from 'react';
import { useNavigate, Link } from 'react-router-dom';
import MovieForm from '../components/MovieForm';
import { moviesAPI } from '../utils/api';
import '../styles/AddMovie.css';

const AddMovie = () => {
  const navigate = useNavigate();

  const handleSubmit = async (formData) => {
    try {
      await moviesAPI.create(formData);
      navigate('/movies');
    } catch (error) {
      console.error('Error creating movie:', error);
      alert('Failed to create movie');
    }
  };

  return (
    <div className="auth-body">
      {/* Контейнер в точности как на странице Login */}
      <div className="container movie-container">
        
        {/* Левая часть с формой */}
        <div className="form-box add-movie-box">
          <MovieForm 
            onSubmit={handleSubmit}
            buttonText="Add Movie"
          />
        </div>

        {/* Правая синяя часть (статичная) */}
        <div className="toggle-box static-toggle">
          <div className="toggle-panel static-panel">
            <h1>Filmery</h1>
            <p>Your personal movie tracking companion. Fill in the details to add a new title to your watchlist.</p>
            <Link to="/movies">
              <button className="btn transparent-btn">Back to Watchlist</button>
            </Link>
          </div>
        </div>

      </div>
    </div>
  );
};

export default AddMovie;
